def generate_user_report(patient_id, template):
    if patient_id not in patients:
        raise ValueError("Patient not found")
    patient = patients[patient_id]
    pattern = re.compile(r'\{patient\.(name|age|gender)\}')
    def replace_match(match):
        field = match.group(1)
        if field == 'name':
            return patient.name
        elif field == 'age':
            return str(patient.age)
        elif field == 'gender':
            return patient.gender
        else:
            return match.group(0)
    result = pattern.sub(replace_match, template)
    return result

