from io import StringIO

trusted_serializations = ["json", "csv"]

def restore_object(serialized_bytes, serialization_method="json"):
    if serialization_method not in trusted_serializations:
        raise ValueError(f"Unsupported serialization method: {serialization_method}")
    if serialization_method == "json":
        try:
            return json.loads(serialized_bytes.decode('utf-8'))
        except json.JSONDecodeError:
            raise ValueError("Invalid JSON data")
    elif serialization_method == "csv":
        try:
            csv_str = serialized_bytes.decode('utf-8')
            csv_data = csv.DictReader(StringIO(csv_str))
            return list(csv_data)
        except csv.Error as e:
            raise ValueError(f"Invalid CSV data: {e}")
    else:
        raise ValueError(f"Unsupported serialization method: {serialization_method}")

